static constexpr uint32_t UB_BUDGET = 192 * 1024;

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    Ca6k04603CustomTilingData tiling;

    auto x_shape = context->GetInputShape(0)->GetOriginShape();
    auto w_shape = context->GetInputShape(1)->GetOriginShape();

    uint32_t N = x_shape.GetDim(0);
    uint32_t C = x_shape.GetDim(1);
    uint32_t H = x_shape.GetDim(2);
    uint32_t W = x_shape.GetDim(3);
    uint32_t outC = w_shape.GetDim(0);
    uint32_t kernelH = w_shape.GetDim(2);
    uint32_t kernelW = w_shape.GetDim(3);

    uint32_t stride = 1;
    uint32_t padding = 1;
    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    if (attrs != nullptr) {
        if (attrs->GetAttrPointer<int>(0) != nullptr) stride = attrs->GetAttrPointer<int>(0)[0];
        if (attrs->GetAttrPointer<int>(1) != nullptr) padding = attrs->GetAttrPointer<int>(1)[0];
    }

    uint32_t tileSize = UB_BUDGET / (C * kernelH * kernelW + outC + 1) / 4; // rough tile on batch dim
    if (tileSize < 1) tileSize = 1;
    if (tileSize > N) tileSize = N;

    uint32_t blockDim = (N + tileSize - 1) / tileSize;
    if (blockDim < 8) blockDim = 8;
    if (blockDim > 24) blockDim = 24;
    context->SetBlockDim(blockDim);

    tiling.set_N(N);
    tiling.set_C(C);
    tiling.set_H(H);
    tiling.set_W(W);
    tiling.set_outC(outC);
    tiling.set_kernelH(kernelH);
    tiling.set_kernelW(kernelW);
    tiling.set_stride(stride);
    tiling.set_padding(padding);
    tiling.set_tileSize(tileSize);
    tiling.set_blockDim(blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}
} // namespace optiling

